#!/usr/bin/env node
// AUTO-GENERATED skill content injector for ccaudit.
// Reads apps/ccaudit/.claude/commands/ccaudit-bust.md and writes
// apps/ccaudit/src/cli/commands/_skill-content.ts as a bundleable TS constant.
// Runs on prebuild hook — do not call directly in normal workflows.

import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const here = path.dirname(fileURLToPath(import.meta.url));
const mdPath = path.resolve(here, '..', '.claude', 'commands', 'ccaudit-bust.md');
const outPath = path.resolve(here, '..', 'src', 'cli', 'commands', '_skill-content.ts');

const raw = await readFile(mdPath, 'utf8');

// Escape characters that would break a JS template literal:
//   backticks  → \`
//   ${ opener → \${
const escaped = raw.replace(/`/g, '\\`').replace(/\$\{/g, '\\${');

const content =
  '// AUTO-GENERATED by scripts/gen-skill-content.mjs — do not edit by hand.\n' +
  '// Sourced from apps/ccaudit/.claude/commands/ccaudit-bust.md at build/test time.\n' +
  'export const CCAUDIT_BUST_SKILL_CONTENT = `' +
  escaped +
  '`;\n';

await mkdir(path.dirname(outPath), { recursive: true });
await writeFile(outPath, content, 'utf8');

console.log(`[gen-skill-content] wrote ${outPath} (${raw.length} chars)`);
